VALUES
  ('locality-6e2f88c7-moex-00156', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列何者非屬權利之原始取得？', '["無主物先占", "法院拍賣", "動產所有權之時效取得", "土地徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00157', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於遺產分割之敘述，何者錯誤？', '["繼承人有數人時，在分割遺產前，各繼承人對於遺產全部為公同共有", "繼承人得隨時請求分割遺產。但法律另有規定或契約另有訂定者，不在此限", "各繼承人對於繼承之公同共有不動產之分割請求權，性質上為具有一身專屬權利", "分割遺產之行為，因其發生權利之變動，其係屬處分行為之一種"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00158', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲向乙銀行貸款新臺幣1,000萬元，雙方約定甲應以其所有之A屋為乙銀行設定普通抵押權。關 於雙方就A屋設定普通抵押權之約定，下列敘述何者正確？', '["債權契約", "物權契約", "準物權契約", "準處分行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00159', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲所有之A土地，由乙在其上建有B屋一棟。下列敘述何者正確？', '["倘若乙係於甲將A土地設定普通抵押權於丙前，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給丁並辦理移轉登記，丙得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙後，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給丁並辦理移轉登記，丙不得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙後，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給甲並辦理移轉登記，丙得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙前，無權在甲所有之A土地上建築B屋，嗣乙將 B屋出售給丁並辦理移轉登記，丙得對B屋主張併付拍賣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00160', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於不動產役權特性之敘述，何者錯誤？', '["不動產役權不得由需役不動產分離而為讓與，此為不動產役權從屬性之表現", "不動產役權不得由供役不動產分離而為其他權利之標的物，此為不動產役權從屬性之表現", "需役不動產經分割者，原則上不動產役權為各部分之利益仍為存續，此為不動產役權不可分性 之表現", "供役不動產經分割者，原則上不動產役權就其各部分仍為存續，此為不動產役權不可分性之 表現 31670 32070"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00161', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '抵押權人於債權已屆清償期，而未受清償者，得實行抵押權。下列何者不屬抵押權之實行方法？', '["法院拍賣", "流押契約之執行", "拍賣以外之方法", "行使抵押權之必要保全處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00162', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲、乙、丙為三兄弟，甲與丁結婚，丙與戊結婚，乙未婚但認領庚。己為戊之妹。下列關於親屬 關係之敘述，何者錯誤？', '["丁庚間無親屬關係", "庚戊間為姻親關係", "己庚間無親屬關係", "丁戊間為姻親關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00163', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲男乙女為夫妻，因乙女與丁男通姦，甲、乙乃於民國（下同）105年3月1日辦妥協議離婚登 記。105年4月1日乙女與丙男辦理結婚登記。同年12月1日乙女生下一子戊。事實上，戊之生 父為丁。下列敘述何者錯誤？', '["戊可推定為甲男之子", "戊可推定為丙男之子", "丁得認領戊", "戊可同時推定為甲男、丙男之子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00164', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲男乙女為夫妻，有一子丙。丙已成年，未婚無子。甲之母丁尚生存。若甲、丙同時死亡，下列 關於丙之遺產繼承之敘述，何者正確？', '["乙繼承甲遺產三分之二、丁繼承甲遺產三分之一；乙繼承丙遺產全部", "甲、乙共同繼承丙之遺產，然後再由乙單獨繼承甲之全部遺產", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產三分之二、丁繼承丙遺產三分 之一", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產全部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00165', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '密封遺囑為要式行為，若不具備法定方式，其效力如何？', '["遺囑效力未定，得隨時拒絕承認", "須經遺囑人的承認後，並經公證，始發生效力", "經法院認可後，得為有效", "密封遺囑雖然無效，然若具備自書遺囑之方式者，有自書遺囑之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
